import re
from tinylang.__init__ import Token

def tokenize(source: str) -> list[Token]:
    tokens = []
    line = 1
    col = 1

    keywords = {
        'let', 'if', 'else', 'while', 'for', 'in', 'fn', 'return', 'break', 'continue',
        'true', 'false', 'nil'
    }

    punctuations = {
        '+', '-', '*', '/', '%', '==', '!=', '<', '>', '<=', '>=', '&&', '||', '!',
        '=', '(', ')', '{', '}', '[', ']', ',', ';', ':', '.'
    }

    token_specification = [
        ('NUMBER',   r'\b\d+(\.\d*)?\b'),
        ('STRING',   r'"([^"\\]*(\\.[^"\\]*)*)"'),
        ('IDENT',    r'\b[A-Za-z_][A-Za-z0-9_]*\b'),
        ('SKIP',     r'[ \t]+'),
        ('COMMENT',  r'//.*'),
        ('NEWLINE',  r'\n'),
        ('PUNCT',    r'[+\-*/%<>=!&|(){}\[\],;:.]+'),
    ]

    tok_regex = '|'.join('(?P<%s>%s)' % pair for pair in token_specification)

    for mo in re.finditer(tok_regex, source):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'NUMBER':
            value = float(value)
        elif kind == 'STRING':
            value = value[1:-1].encode('utf-8').decode('unicode_escape')
        elif kind == 'IDENT':
            if value in keywords:
                kind = 'KEYWORD'
        elif kind == 'SKIP':
            continue
        elif kind == 'COMMENT':
            continue
        elif kind == 'NEWLINE':
            line += 1
            col = 1
            continue
