            for punct in punctuations:
                if value.startswith(punct):
                    kind = 'PUNCT'
                    value = punct
                    break

        tokens.append(Token(kind, value, line, col))
        col += len(value)

    tokens.append(Token('EOF', None, line, col))
    return tokens
